srcDoc.css:
* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  background: #f8fafc;
  padding: 12px;
}

.collection-card {
  background: #fff;
  border-radius: 12px;
  padding: 14px 16px;
  margin-bottom: 10px;
  border: 1px solid #e2e8f0;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.card-top {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
}

.customer-name {
  font-size: 15px;
  font-weight: 700;
  color: #1e293b;
}

.status-badge {
  font-size: 11px;
  font-weight: 600;
  padding: 3px 8px;
  border-radius: 20px;
  white-space: nowrap;
}

.status-booked {
  background: #e0f2fe;
  color: #0369a1;
}

.status-collected {
  background: #fef3c7;
  color: #92400e;
}

.status-received {
  background: #ffedd5;
  color: #c2410c;
}

.status-booking-complete {
  background: #dcfce7;
  color: #15803d;
}

.status-default {
  background: #f1f5f9;
  color: #64748b;
}

.card-meta {
  display: flex;
  gap: 12px;
  align-items: center;
}

.meta-item {
  font-size: 12px;
  color: #64748b;
  display: flex;
  align-items: center;
  gap: 4px;
}

.card-address {
  font-size: 12px;
  color: #94a3b8;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.select-btn {
  width: 100%;
  padding: 10px;
  background: #085041;
  color: #fff;
  border: none;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  margin-top: 4px;
}

.select-btn:active {
  background: #064035;
}

.empty {
  text-align: center;
  color: #94a3b8;
  font-size: 14px;
  padding: 40px 20px;
}

