function fmtDate(d) {
  if (!d) return '—';
  const dt = new Date(d);
  if (isNaN(dt.getTime())) return d;
  return dt.toLocaleDateString('en-GB', {
    day: 'numeric',
    month: 'short',
    year: 'numeric'
  });
}
function getStatusClass(status) {
  if (!status) return 'status-default';
  const s = status.toLowerCase().replace(/\s+/g, '-');
  if (s.includes('booked') && !s.includes('complete')) return 'status-booked';
  if (s.includes('collected')) return 'status-collected';
  if (s.includes('received')) return 'status-received';
  if (s.includes('complete')) return 'status-booking-complete';
  return 'status-default';
}
function render() {
  const model = appsmith.model || {};
  const collections = Array.isArray(model.collections) ? model.collections : [];
  const root = document.getElementById('root');
  if (!collections.length) {
    root.innerHTML = '<div class="empty">No collections found</div>';
    return;
  }
  root.innerHTML = collections.map(function (c) {
    return '<div class="collection-card">' + '<div class="card-top">' + '<div class="customer-name">' + (c.customer_name || '—') + '</div>' + '<span class="status-badge ' + getStatusClass(c.status) + '">' + (c.status || '—') + '</span>' + '</div>' + '<div class="card-meta">' + '<span class="meta-item">📅 ' + fmtDate(c.collection_date) + '</span>' + '<span class="meta-item"># ' + (c.collection_id || '—') + '</span>' + '</div>' + '<div class="card-address">📍 ' + (c.address1 || '') + (c.city ? ', ' + c.city : '') + '</div>' + '<button class="select-btn" onclick="selectCollection(' + JSON.stringify(c.collection_id) + ')">Select Collection</button>' + '</div>';
  }).join('');
}
window.selectCollection = function (id) {
  appsmith.updateModel({
    selectedId: id
  });
  appsmith.triggerEvent('onSelect');
};
appsmith.onReady(function () {
  render();
  appsmith.onModelChange(render);
});

